import { describe, expect, it } from 'vitest';

import { CostAlgebraViolation } from '../src/cost-algebra-enforcement';
import {
  costlyBroadcast,
  smartBroadcast,
  vacuumBroadcast,
} from '../src/cost-algebra-broadcast';
import {
  TOWER_CEILINGS,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

describe('vacuumBroadcast — future-pillar gate', () => {
  it('passes a vacuum-carrier broadcast to N recipients with cost 0', () => {
    const result = vacuumBroadcast({
      payload: { kind: 'config', value: 42 },
      carrier: vacuumBuleyProjection,
      recipients: ['node-a', 'node-b', 'node-c'],
    });
    expect(result.fanout).toBe(3);
    expect(result.cost).toBe(0);
    expect(result.payload).toEqual({ kind: 'config', value: 42 });
  });

  it('throws CostAlgebraViolation on a non-vacuum carrier', () => {
    const carrier: BuleyProjection = {
      waste: 1,
      opportunity: 0,
      diversity: 0,
      score: 1,
    };
    try {
      vacuumBroadcast({
        payload: 'will-not-fan-out',
        carrier,
        recipients: ['node-a'],
      });
      expect.fail('expected throw');
    } catch (e) {
      expect(e).toBeInstanceOf(CostAlgebraViolation);
      expect((e as CostAlgebraViolation).gate).toBe('pillar-future');
    }
  });

  it('rejects a Hexon-edge carrier (score 6)', () => {
    const carrier: BuleyProjection = {
      waste: 6,
      opportunity: 0,
      diversity: 0,
      score: 6,
    };
    expect(() =>
      vacuumBroadcast({ payload: null, carrier, recipients: ['x'] }),
    ).toThrow(CostAlgebraViolation);
  });

  it('handles zero recipients (no fan-out)', () => {
    const result = vacuumBroadcast({
      payload: 'noop',
      carrier: vacuumBuleyProjection,
      recipients: [],
    });
    expect(result.fanout).toBe(0);
    expect(result.cost).toBe(0);
  });
});

describe('costlyBroadcast — Landauer-ceiling gate', () => {
  it('admits a Hexon-pressure carrier replicating to 2 nodes at ceiling 12', () => {
    const carrier: BuleyProjection = {
      waste: 6,
      opportunity: 0,
      diversity: 0,
      score: 6,
    };
    const result = costlyBroadcast({
      payload: 'state-update',
      carrier,
      recipients: ['node-a', 'node-b'],
      ceiling: 12,
    });
    expect(result.admission.admitted).toBe(true);
    expect(result.admission.totalHeat).toBe(12);
    expect(result.replicationEntropy).toBe(6); // (k-1)*score = 1*6
  });

  it('throws on Trihexon carrier replicating to 2 nodes at default Hexon ceiling', () => {
    const carrier: BuleyProjection = {
      waste: 18,
      opportunity: 0,
      diversity: 0,
      score: 18,
    };
    expect(() =>
      costlyBroadcast({
        payload: null,
        carrier,
        recipients: ['n1', 'n2'],
      }),
    ).toThrow(CostAlgebraViolation);
  });

  it('default ceiling is the Hexon = 6', () => {
    const carrier: BuleyProjection = {
      waste: 7,
      opportunity: 0,
      diversity: 0,
      score: 7,
    };
    try {
      costlyBroadcast({ payload: null, carrier, recipients: ['n1'] });
      expect.fail('expected throw');
    } catch (e) {
      expect(e).toBeInstanceOf(CostAlgebraViolation);
      // 1 replica at score 7, ceiling 6: deficit 1
      expect((e as CostAlgebraViolation).context).toMatchObject({
        ceiling: TOWER_CEILINGS.hexon,
      });
    }
  });

  it('reports replication entropy correctly for k=3 fan-out', () => {
    const carrier: BuleyProjection = {
      waste: 2,
      opportunity: 0,
      diversity: 0,
      score: 2,
    };
    const result = costlyBroadcast({
      payload: 'x',
      carrier,
      recipients: ['a', 'b', 'c'],
      ceiling: 100,
    });
    expect(result.replicationEntropy).toBe(4); // (3-1)*2
    expect(result.admission.totalHeat).toBe(6); // score + entropy
  });
});

describe('smartBroadcast — discriminated dispatch', () => {
  it('routes vacuum carriers through the vacuum path', () => {
    const result = smartBroadcast(
      { kind: 'heartbeat' },
      vacuumBuleyProjection,
      ['node-a', 'node-b'],
    );
    expect(result.kind).toBe('vacuum');
    if (result.kind === 'vacuum') {
      expect(result.result.cost).toBe(0);
      expect(result.result.fanout).toBe(2);
    }
  });

  it('routes non-vacuum carriers through the costly path', () => {
    const carrier: BuleyProjection = {
      waste: 2,
      opportunity: 1,
      diversity: 0,
      score: 3,
    };
    const result = smartBroadcast(
      'state',
      carrier,
      ['a', 'b'],
      TOWER_CEILINGS.hexon,
    );
    expect(result.kind).toBe('costly');
    if (result.kind === 'costly') {
      expect(result.result.replicationEntropy).toBe(3);
      expect(result.result.admission.admitted).toBe(true);
    }
  });

  it('smartBroadcast still throws on costly path violations', () => {
    const carrier: BuleyProjection = {
      waste: 18,
      opportunity: 0,
      diversity: 0,
      score: 18,
    };
    expect(() =>
      smartBroadcast('payload', carrier, ['a', 'b'], TOWER_CEILINGS.hexon),
    ).toThrow(CostAlgebraViolation);
  });
});
